export function parseArgs(argv) {
  const result = { _: [] }
  let index = 0

  while (index < argv.length) {
    const arg = argv[index]

    // Positional arguments
    if (!arg.startsWith('-')) {
      result._.push(arg)
      index += 1
      continue
    }

    if (arg.startsWith('--')) {
      const value = arg
      const nextIndex = index + 1

      // --key=value syntax
      const equalsIndex = value.indexOf('=')
      if (equalsIndex >= 0) {
        const key = value.slice(0, equalsIndex)
        const val = value.slice(equalsIndex + 1)
        result[key] = val
        index += 1
        continue
      }

      // --key value or --key (boolean)
      index += 1
      if (index < argv.length) {
        const nextArg = argv[index]
        if (!nextArg.startsWith('--')) {
          result[value] = nextArg
        }
      }
    } else {
      // -k syntax (single dash boolean)
      result[arg] = true
      index += 1
    }
  }

  return result
}

